/**
 * Search the local database.
 * @param {string} rawName - drug name as entered by user
 * @returns {{ drug: object|null, confidence: 'exact'|'partial'|null }}
 */
function searchLocalDB(rawName) {
  const norm = normalizeName(rawName);
  if (!norm) return { drug: null, confidence: null };

  for (const entry of DRUGDB) {
    for (const kw of entry.keywords) {
      const kwNorm = normalizeName(kw);
      if (kwNorm === norm) return { drug: entry, confidence: 'exact' };
    }
  }
  // Partial match
  for (const entry of DRUGDB) {
    for (const kw of entry.keywords) {
      const kwNorm = normalizeName(kw);
      if (kwNorm.includes(norm) || norm.includes(kwNorm)) {
        return { drug: entry, confidence: 'partial' };
      }
    }
  }
  return { drug: null, confidence: null };
}

function normalizeName(str) {
  // 半角カタカナ → 全角カタカナ（OCR出力の揺れに対応）
  const dakuten = [
    ['ｶﾞ','ガ'],['ｷﾞ','ギ'],['ｸﾞ','グ'],['ｹﾞ','ゲ'],['ｺﾞ','ゴ'],
    ['ｻﾞ','ザ'],['ｼﾞ','ジ'],['ｽﾞ','ズ'],['ｾﾞ','ゼ'],['ｿﾞ','ゾ'],
    ['ﾀﾞ','ダ'],['ﾁﾞ','ヂ'],['ﾂﾞ','ヅ'],['ﾃﾞ','デ'],['ﾄﾞ','ド'],
    ['ﾊﾞ','バ'],['ﾋﾞ','ビ'],['ﾌﾞ','ブ'],['ﾍﾞ','ベ'],['ﾎﾞ','ボ'],['ｳﾞ','ヴ'],
    ['ﾊﾟ','パ'],['ﾋﾟ','ピ'],['ﾌﾟ','プ'],['ﾍﾟ','ペ'],['ﾎﾟ','ポ'],
  ];
  let s = str;
  for (const [h, z] of dakuten) s = s.split(h).join(z);
  const hkMap = {
    'ｦ':'ヲ','ｧ':'ァ','ｨ':'ィ','ｩ':'ゥ','ｪ':'ェ','ｫ':'ォ',
    'ｬ':'ャ','ｭ':'ュ','ｮ':'ョ','ｯ':'ッ','ｰ':'ー',
    'ｱ':'ア','ｲ':'イ','ｳ':'ウ','ｴ':'エ','ｵ':'オ',
    'ｶ':'カ','ｷ':'キ','ｸ':'ク','ｹ':'ケ','ｺ':'コ',
    'ｻ':'サ','ｼ':'シ','ｽ':'ス','ｾ':'セ','ｿ':'ソ',
    'ﾀ':'タ','ﾁ':'チ','ﾂ':'ツ','ﾃ':'テ','ﾄ':'ト',
    'ﾅ':'ナ','ﾆ':'ニ','ﾇ':'ヌ','ﾈ':'ネ','ﾉ':'ノ',
    'ﾊ':'ハ','ﾋ':'ヒ','ﾌ':'フ','ﾍ':'ヘ','ﾎ':'ホ',
    'ﾏ':'マ','ﾐ':'ミ','ﾑ':'ム','ﾒ':'メ','ﾓ':'モ',
    'ﾔ':'ヤ','ﾕ':'ユ','ﾖ':'ヨ',
    'ﾗ':'ラ','ﾘ':'リ','ﾙ':'ル','ﾚ':'レ','ﾛ':'ロ',
    'ﾜ':'ワ','ﾝ':'ン',
  };
  s = s.split('').map(c => hkMap[c] ?? c).join('');

  return s
    .replace(/\d+(\.\d+)?\s*(mg|mL|μg|mcg|IU|%|g|単位|u)/gi, '')
    .replace(/(錠|カプセル|cap|tab|注射液|注|液|散|粉|顆粒|テープ|パッチ|クリーム|軟膏|点眼|点鼻|吸入|スプレー|ゼリー|トローチ|シリンジ|袋|包)/g, '')
    .replace(/（.*?）|\(.*?\)/g, '')
    .replace(/[　 \s]+/g, '')
    .replace(/[Ａ-Ｚａ-ｚ０-９]/g, c => String.fromCharCode(c.charCodeAt(0) - 0xFEE0))
    .toLowerCase()
    .trim();
}
